# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import pymysql
import os

def search_database(request):
    # Connect to Cloud SQL database
    db_name = os.environ['DB_NAME']
    db_user = os.environ['DB_USER']
    db_password = os.environ['DB_PASSWORD']
    db_host = os.environ['DB_HOST']

    connection = pymysql.connect(
        host=db_host,
        user=db_user,
        password=db_password,
        database=db_name
    )

    # Get request parameters
    search_term = request.args.get('search_term')
    category = request.args.get('category')
    price_range = request.args.get('price_range')

    # Build SQL query dynamically
    query = "SELECT * FROM products WHERE 1=1"

    if search_term:
        query += " AND name LIKE '%{}%'".format(search_term)

    if category:
        query += " AND category = '{}'".format(category)

    if price_range:
        min_price, max_price = price_range.split('-')
        query += " AND price BETWEEN {} AND {}".format(min_price, max_price)

    # Execute SQL query
    cursor = connection.cursor()
    cursor.execute(query)

    # Return results
    results = cursor.fetchall()
    cursor.close()
    connection.close()

    return results